const logicItem = $('Get GOLD Logic Document').first().json;
const marketItem = $('Build GOLD Input Pack').first().json;

let logicDocument = logicItem.content || '';

if (logicItem.encoding === 'base64') {
  logicDocument = Buffer.from(logicDocument, 'base64').toString('utf8');
}

return [
  {
    json: {
      logic_document: logicDocument,
      market_snapshot: marketItem
    }
  }
];

const item = $input.first().json;
const inputs = item.market_inputs || {};

function n(v) {
  const x = Number(v);
  return Number.isFinite(x) ? x : null;
}

function makeFactor(signal, evidence, reason) {
  return { signal, evidence, reason };
}

function safeJson(value) {
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value || "");
  }
}

const TIMEFRAME_WEIGHTS = {
  "24h": {
    F1: 26, F2: 22, F3: 12, F4: 10, F5: 10,
    F6: 8, F7: 8, F8: 2, F9: 1, F10: 1
  },
  "3d": {
    F1: 24, F2: 20, F3: 14, F4: 10, F5: 8,
    F6: 10, F7: 6, F8: 4, F9: 3, F10: 1
  },
  "current_week": {
    F1: 22, F2: 18, F3: 16, F4: 10, F5: 8,
    F6: 10, F7: 5, F8: 5, F9: 4, F10: 2
  },
  "next_week": {
    F1: 20, F2: 16, F3: 18, F4: 10, F5: 6,
    F6: 8, F7: 4, F8: 8, F9: 6, F10: 4
  },
  "current_month": {
    F1: 18, F2: 16, F3: 18, F4: 10, F5: 6,
    F6: 6, F7: 4, F8: 10, F9: 6, F10: 6
  }
};

function factorSignals(tf) {
  const use20d = tf === "next_week" || tf === "current_month";

  const realYieldDelta =
    use20d && n(inputs.us_10y_real_yield_d20_bps) !== null
      ? n(inputs.us_10y_real_yield_d20_bps)
      : n(inputs.us_10y_real_yield_d5_bps);

  const dxyDelta =
    use20d && n(inputs.dxy_d20) !== null
      ? n(inputs.dxy_d20)
      : tf === "24h" && n(inputs.dxy_d1) !== null
        ? n(inputs.dxy_d1)
        : n(inputs.dxy_d5);

  const goldDelta =
    use20d && n(inputs.gold_d20_pct) !== null
      ? n(inputs.gold_d20_pct)
      : tf === "24h" && n(inputs.gold_d1_pct) !== null
        ? n(inputs.gold_d1_pct)
        : n(inputs.gold_d5_pct);

  const us2yDelta =
    use20d && n(inputs.us_2y_d20_bps) !== null
      ? n(inputs.us_2y_d20_bps)
      : n(inputs.us_2y_d5_bps);

  const vix = n(inputs.vix_level);
  const fed = String(inputs.fed_bias || "").toLowerCase();

  const growth = String(
    inputs.global_growth_regime ||
    inputs.growth_regime ||
    ""
  ).toLowerCase();

  const geopoliticalFlag =
    inputs.geopolitical_risk_flag === true ||
    inputs.geopolitical_risk_flag === "true";

  const riskText = String(
    inputs.risk_headline_context ||
    (geopoliticalFlag ? "stress" : "")
  ).toLowerCase();

  const signals = {};

  signals.F1 = (() => {
    if (realYieldDelta === null) {
      return makeFactor("NEUTRAL", "Missing real yield delta", "Missing input");
    }

    if (realYieldDelta <= -5) {
      return makeFactor("BULLISH", `Real yield ${realYieldDelta}bps`, "Falling real yields support Gold");
    }

    if (realYieldDelta >= 5) {
      return makeFactor("BEARISH", `Real yield ${realYieldDelta}bps`, "Rising real yields pressure Gold");
    }

    return makeFactor("NEUTRAL", `Real yield ${realYieldDelta}bps`, "Real yield move below threshold");
  })();

  signals.F2 = (() => {
    if (dxyDelta === null) {
      return makeFactor("NEUTRAL", "Missing DXY delta", "Missing input");
    }

    const threshold = tf === "24h" ? 0.15 : 0.3;

    if (dxyDelta <= -threshold) {
      return makeFactor("BULLISH", `DXY ${dxyDelta}%`, "Dollar weakness supports Gold");
    }

    if (dxyDelta >= threshold) {
      return makeFactor("BEARISH", `DXY ${dxyDelta}%`, "Dollar strength pressures Gold");
    }

    return makeFactor("NEUTRAL", `DXY ${dxyDelta}%`, "DXY move below threshold");
  })();

  signals.F3 = (() => {
    if (!fed || fed === "unknown") {
      return makeFactor("NEUTRAL", "Fed bias unknown", "Missing input");
    }

    if (fed.includes("dovish")) {
      return makeFactor("BULLISH", `Fed bias ${fed}`, "Dovish Fed supports Gold through lower real-yield and liquidity expectations");
    }

    if (fed.includes("hawkish")) {
      return makeFactor("BEARISH", `Fed bias ${fed}`, "Hawkish Fed pressures Gold through higher real-yield and policy-rate expectations");
    }

    return makeFactor("NEUTRAL", `Fed bias ${fed}`, "No clear Fed impulse");
  })();

  signals.F4 = (() => {
    if (us2yDelta === null) {
      return makeFactor("NEUTRAL", "Missing US 2Y delta", "Missing input");
    }

    if (us2yDelta <= -5) {
      return makeFactor("BULLISH", `US 2Y ${us2yDelta}bps`, "Falling front-end yields support Gold");
    }

    if (us2yDelta >= 5) {
      return makeFactor("BEARISH", `US 2Y ${us2yDelta}bps`, "Rising front-end yields pressure Gold");
    }

    return makeFactor("NEUTRAL", `US 2Y ${us2yDelta}bps`, "US 2Y move below threshold");
  })();

  signals.F5 = (() => {
    if (goldDelta === null) {
      return makeFactor("NEUTRAL", "Missing Gold delta", "Missing input");
    }

    const threshold = tf === "24h" ? 0.3 : 0.5;

    if (goldDelta >= threshold) {
      return makeFactor("BULLISH", `Gold ${goldDelta}%`, "Gold own-price trend confirms upside pressure");
    }

    if (goldDelta <= -threshold) {
      return makeFactor("BEARISH", `Gold ${goldDelta}%`, "Gold own-price trend confirms downside pressure");
    }

    return makeFactor("NEUTRAL", `Gold ${goldDelta}%`, "Gold price move below threshold");
  })();

  signals.F6 = (() => {
    if (vix === null) {
      return makeFactor("NEUTRAL", "Missing VIX", "Missing input");
    }

    if (vix > 25) {
      return makeFactor("BULLISH", `VIX ${vix}`, "Risk-off conditions support Gold safe-haven demand");
    }

    if (vix < 16) {
      return makeFactor("BEARISH", `VIX ${vix}`, "Risk-on conditions reduce defensive Gold demand");
    }

    return makeFactor("NEUTRAL", `VIX ${vix}`, "Neutral risk regime");
  })();

  signals.F7 = (() => {
    const ev = inputs.latest_us_event;
    const text = safeJson(ev).toLowerCase();

    if (!ev || text === "{}") {
      return makeFactor("NEUTRAL", "No recent US event", "No confirmed US economic surprise");
    }

    if (
      text.includes("negative") ||
      text.includes("miss") ||
      text.includes("bearish")
    ) {
      return makeFactor("BULLISH", safeJson(ev), "Negative US surprise supports Gold through lower yield and Fed repricing risk");
    }

    if (
      text.includes("positive") ||
      text.includes("beat") ||
      text.includes("bullish")
    ) {
      return makeFactor("BEARISH", safeJson(ev), "Positive US surprise pressures Gold through higher yield and Fed repricing risk");
    }

    return makeFactor("NEUTRAL", safeJson(ev), "No clear Gold signal from latest US event");
  })();

  signals.F8 = (() => {
    return makeFactor(
      "NEUTRAL",
      "Inflation signal unavailable",
      "Collector does not currently provide a top-level inflation_signal column"
    );
  })();

  signals.F9 = (() => {
    if (
      riskText.includes("safe_haven") ||
      riskText.includes("stress") ||
      riskText.includes("crisis") ||
      riskText.includes("risk_active")
    ) {
      return makeFactor("BULLISH", riskText, "Safe-haven demand supports Gold");
    }

    return makeFactor("NEUTRAL", riskText || "normal", "No active safe-haven demand signal");
  })();

  signals.F10 = (() => {
    if (
      growth.includes("weakening") ||
      growth.includes("contraction")
    ) {
      return makeFactor("BULLISH", growth, "Weakening growth supports Gold through defensive demand and lower yield expectations");
    }

    if (
      growth.includes("supportive") ||
      growth.includes("expansion")
    ) {
      return makeFactor("BEARISH", growth, "Supportive growth reduces defensive Gold demand and can lift yields");
    }

    return makeFactor("NEUTRAL", growth || "neutral", "No clear growth or liquidity signal");
  })();

  return signals;
}

function scoreTimeframe(tf) {
  const weights = TIMEFRAME_WEIGHTS[tf];
  const signals = factorSignals(tf);

  let bullish = 0;
  let bearish = 0;
  let neutral = 0;

  let bullishCount = 0;
  let bearishCount = 0;
  let neutralCount = 0;

  const factorBreakdown = {};

  for (const [id, sig] of Object.entries(signals)) {
    const weight = weights[id] || 0;

    factorBreakdown[id] = { ...sig, weight };

    if (sig.signal === "BULLISH") {
      bullish += weight;
      bullishCount++;
    } else if (sig.signal === "BEARISH") {
      bearish += weight;
      bearishCount++;
    } else {
      neutral += weight;
      neutralCount++;
    }
  }

  const active = bullish + bearish;
  const participation = active;

  const bullishArgument = active > 0 ? Math.round((bullish / active) * 100) : 0;
  const bearishArgument = active > 0 ? Math.round((bearish / active) * 100) : 0;
  const neutralPct = Math.round(neutral);
  const netEdge = bullishArgument - bearishArgument;

  const baseDirection =
    bullish > bearish
      ? "BULLISH"
      : bearish > bullish
        ? "BEARISH"
        : "NO_CLEAR_BIAS";

  const absEdge = Math.abs(netEdge);
  const weightMargin = Math.abs(bullish - bearish);

  const direction =
    baseDirection === "NO_CLEAR_BIAS"
      ? "NO_CLEAR_BIAS"
      : active < 50 || weightMargin < 15 || absEdge < 20
        ? `${baseDirection}_LEAN`
        : baseDirection;

  const winningArgument =
    baseDirection === "BULLISH"
      ? bullishArgument
      : baseDirection === "BEARISH"
        ? bearishArgument
        : 0;

  const participationCap = Math.min(participation, 80);

  const conviction =
    baseDirection === "NO_CLEAR_BIAS"
      ? 0
      : Math.round(winningArgument * (participationCap / 100));

  const strength =
    absEdge >= 40 && participation >= 70 ? "VERY_STRONG" :
    absEdge >= 25 && participation >= 50 ? "STRONG" :
    absEdge >= 15 ? "MODERATE" :
    "WEAK";

  const reason =
    `${tf} deterministic Gold score: bull case ${bullishArgument}%, bear case ${bearishArgument}%, directional participation ${participation}%, neutral/inactive ${neutralPct}%, net edge ${netEdge > 0 ? "+" : ""}${netEdge}. Real yields and DXY remain the highest-priority Gold drivers.`;

  return {
    direction,
    conviction,
    reason,
    factor_breakdown: factorBreakdown,
    score_bullish: bullishCount,
    score_bearish: bearishCount,
    score_neutral: neutralCount,
    weighted_score: {
      bullish_weight: bullish,
      bearish_weight: bearish,
      neutral_weight: neutral,
      active_weight: active,
      weight_margin: weightMargin
    },
    conviction_model: {
      bull_case: bullishArgument,
      bear_case: bearishArgument,
      winning_side: baseDirection,
      directional_participation: participation,
      net_edge: netEdge,
      final_conviction: conviction,
      verdict_strength: strength,
      final_conviction_logic: reason,

      bullish_argument_pct: bullishArgument,
      bearish_argument_pct: bearishArgument,
      neutral_pct: neutralPct,
      active_participation_pct: participation,
      net_edge_pct: netEdge,

      weighted_edge: Math.abs(netEdge) / 100,
      raw_conviction: conviction,
      base_conviction: conviction,
      participation,
      participation_cap: participationCap,
      conflict_penalty: 0,
      missing_input_penalty: 0,
      agreement_boost: 0
    }
  };
}

const r24h = scoreTimeframe("24h");
const r3d = scoreTimeframe("3d");
const rWeek = scoreTimeframe("current_week");
const rNextWeek = scoreTimeframe("next_week");
const rMonth = scoreTimeframe("current_month");

const output = {
  ...(item.full_output || {}),

  asset: "GOLD",
  agent_name: "GOLD",
  logic_document: "agent_gold_direction.md",
  logic_document_version: "2.0_weighted_engine",

  direction_24h: r24h.direction,
  conviction_24h: r24h.conviction,
  reason_24h: r24h.reason,

  direction_3_day: r3d.direction,
  conviction_3_day: r3d.conviction,
  reason_3_day: r3d.reason,

  direction_current_week: rWeek.direction,
  conviction_current_week: rWeek.conviction,
  reason_current_week: rWeek.reason,

  direction_next_week: rNextWeek.direction,
  conviction_next_week: rNextWeek.conviction,
  reason_next_week: rNextWeek.reason,

  direction_current_month: rMonth.direction,
  conviction_current_month: rMonth.conviction,
  reason_current_month: rMonth.reason,

  weighted_score: r24h.weighted_score,
  conviction_model: r24h.conviction_model,
  factor_breakdown: r24h.factor_breakdown,

  timeframe_models: {
    "24h": r24h,
    "3d": r3d,
    "current_week": rWeek,
    "next_week": rNextWeek,
    "current_month": rMonth
  },

  score_bullish: r24h.score_bullish,
  score_bearish: r24h.score_bearish,
  score_neutral: r24h.score_neutral,

  reasoning_summary:
    `GOLD weighted verdicts calculated deterministically by timeframe. ` +
    `24h ${r24h.direction} ${r24h.conviction}%, ` +
    `3d ${r3d.direction} ${r3d.conviction}%, ` +
    `current week ${rWeek.direction} ${rWeek.conviction}%, ` +
    `next week ${rNextWeek.direction} ${rNextWeek.conviction}%, ` +
    `current month ${rMonth.direction} ${rMonth.conviction}%.`
};

const { market_inputs, ...safeItem } = item;

delete safeItem.non_neutral_count;
delete safeItem.missing_inputs;
delete safeItem.timeframe_models;

return [{
  json: {
    ...safeItem,

    agent_name: "GOLD",
    logic_document: "agent_gold_direction.md",
    logic_document_version: "2.0_weighted_engine",

    call_24h_direction: output.direction_24h,
    call_24h_conviction: output.conviction_24h,
    call_24h_reason: output.reason_24h,

    call_3d_direction: output.direction_3_day,
    call_3d_conviction: output.conviction_3_day,
    call_3d_reason: output.reason_3_day,

    call_current_week_direction: output.direction_current_week,
    call_current_week_conviction: output.conviction_current_week,
    call_current_week_reason: output.reason_current_week,

    call_next_week_direction: output.direction_next_week,
    call_next_week_conviction: output.conviction_next_week,
    call_next_week_reason: output.reason_next_week,

    call_current_month_direction: output.direction_current_month,
    call_current_month_conviction: output.conviction_current_month,
    call_current_month_reason: output.reason_current_month,

    direction_24h: output.direction_24h,
    conviction_24h: output.conviction_24h,

    direction_3_day: output.direction_3_day,
    conviction_3_day: output.conviction_3_day,

    direction_current_week: output.direction_current_week,
    conviction_current_week: output.conviction_current_week,

    direction_next_week: output.direction_next_week,
    conviction_next_week: output.conviction_next_week,

    direction_current_month: output.direction_current_month,
    conviction_current_month: output.conviction_current_month,

    factor_breakdown: output.factor_breakdown,
    weighted_score: output.weighted_score,
    conviction_model: output.conviction_model,

    full_output: output,
    raw_agent_output: output,

    reasoning_summary: output.reasoning_summary,
    score_bullish: output.score_bullish,
    score_bearish: output.score_bearish,
    score_neutral: output.score_neutral
  }
}];
